use std::collections::HashSet;

#[derive(Clone, PartialEq)]
pub struct KeyState {
    pub left_shift: bool,
    pub right_shift: bool,
    pub left_control: bool,
    pub right_control: bool,
    pub left_alt: bool,
    pub right_alt: bool,
    pub left_cmd: bool,
    pub right_cmd: bool,
    pub caps_lock: bool,
    pub pressed_order: Vec<u32>,
    pub pressed_set: HashSet<u32>,
}

impl Default for KeyState {
    fn default() -> Self {
        Self {
            left_shift: false,
            right_shift: false,
            left_control: false,
            right_control: false,
            left_alt: false,
            right_alt: false,
            left_cmd: false,
            right_cmd: false,
            caps_lock: false,
            pressed_order: Vec::new(),
            pressed_set: HashSet::new(),
        }
    }
}

impl KeyState {
    pub fn format_output(&self) -> String {
        let modifiers = format!(
            "{} {} {} {} {} {} {} {}",
            if self.left_shift { "LSH" } else { "lsh" },
            if self.right_shift { "RSH" } else { "rsh" },
            if self.left_control { "LCT" } else { "lct" },
            if self.right_control { "RCT" } else { "rct" },
            if self.left_alt { "LAL" } else { "lal" },
